export enum LoadingState {
  IDLE = 'IDLE',
  SEARCHING = 'SEARCHING',
  ANALYZING = 'ANALYZING',
  DRAFTING = 'DRAFTING',
  POLISHING = 'POLISHING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export interface ArticleData {
  title: string;
  subtitle: string;
  author: string; // The original video creator or an AI persona
  content: string; // HTML or Markdown string
  estimatedReadingTime: number;
  tags: string[];
  coverImagePrompts?: string;
  coverImageUrl?: string;
  sourceUrl: string;
}

export interface ProcessingLog {
  stage: LoadingState;
  message: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ArticleData } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY is missing from environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateArticleFromVideo = async (videoUrl: string): Promise<ArticleData> => {
  const ai = getAiClient();

  // 1. Analyze Video & Write Article
  // We use gemini-3-pro-preview for complex reasoning and writing capabilities.
  // We use googleSearch to find the video content/transcript since we can't download it client-side.

  const systemInstruction = `
    You are a world-class non-fiction author and ghostwriter (Persona: A mix of Malcolm Gladwell, Peter Thiel, and a senior editor at The New Yorker).

    Your task is to take a YouTube or Bilibili video URL, understand its full content via Google Search (transcripts, summaries, reviews, metadata), and transmute it into a high-quality, "Deep Read" book chapter.

    GUIDELINES:
    1.  **Format:** A standalone chapter in a bestselling business or philosophy book.
    2.  **Tone:** Intellectual, engaging, narrative-driven, and authoritative. Avoid "video script" language (e.g., "In this video", "Smash like"). Use "In this analysis" or simply state the facts.
    3.  **Structure:** 
        -   **Title:** Catchy, book-worthy title.
        -   **Subtitle:** A compelling hook.
        -   **Content:** Long-form prose. Use <h3> for section breaks. 
        -   **Length:** Prioritize completeness. If the video is dense, write 2000+ words. If short, write a deep 1000 words. Do not summarize for brevity; expand for clarity and insight.
    4.  **Styling:** Return the content in clean Markdown.
    5.  **Detail:** Include specific examples, data points, and arguments mentioned in the video. If the video is a tutorial, turn it into a conceptual framework.
    6.  **Meta:** Also provide an estimated reading time and a prompt to generate a cover image for this chapter.
  `;

  const prompt = `
    Video URL: ${videoUrl}

    Please perform a deep research on this video using Google Search to understand its exact content, transcript, and key arguments. 
    Then, write the "Deep Read" adaptation. 

    Return the output as a JSON object with the following schema:
    {
      "title": "The main title",
      "subtitle": "The subtitle",
      "author": "The channel name or speaker",
      "content": "The full markdown content",
      "tags": ["tag1", "tag2"],
      "coverImagePrompts": "A detailed vivid description for an AI image generator to create a cover art for this chapter (abstract, editorial style)."
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      // Giving it a budget to think deeply about structure before writing
      thinkingConfig: { thinkingBudget: 2048 }, 
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          subtitle: { type: Type.STRING },
          author: { type: Type.STRING },
          content: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
          coverImagePrompts: { type: Type.STRING },
        },
        required: ["title", "subtitle", "author", "content", "tags", "coverImagePrompts"]
      }
    },
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  let parsedData: any;
  try {
    parsedData = JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse JSON", text);
    throw new Error("Failed to parse AI response");
  }

  const article: ArticleData = {
    ...parsedData,
    sourceUrl: videoUrl,
    estimatedReadingTime: Math.ceil(parsedData.content.split(' ').length / 200)
  };

  return article;
};

export const generateCoverImage = async (imagePrompt: string): Promise<string | undefined> => {
  try {
    const ai = getAiClient();
    // Using gemini-3-pro-image-preview for high quality 16:9 editorial headers
    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: imagePrompt,
        config: {
            imageConfig: {
                aspectRatio: "16:9",
                imageSize: "1K"
            }
        }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
  } catch (e) {
    console.warn("Image generation failed, continuing without image", e);
    return undefined;
  }
  return undefined;
};

