import React, { useEffect, useState } from 'react';
import { LoadingState } from '../types';
import { Loader2, Search, Brain, PenTool, Sparkles } from 'lucide-react';

interface ProcessingStateProps {
  state: LoadingState;
}

export const ProcessingState: React.FC<ProcessingStateProps> = ({ state }) => {
  const [dots, setDots] = useState('');

  useEffect(() => {
    const interval = setInterval(() => {
      setDots(prev => prev.length >= 3 ? '' : prev + '.');
    }, 500);
    return () => clearInterval(interval);
  }, []);

  const steps = [
    { id: LoadingState.SEARCHING, label: 'Searching Knowledge Base', icon: Search },
    { id: LoadingState.ANALYZING, label: 'Deconstructing Arguments', icon: Brain },
    { id: LoadingState.DRAFTING, label: 'Drafting Manuscript', icon: PenTool },
    { id: LoadingState.POLISHING, label: 'Polishing Prose', icon: Sparkles },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === state);

  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] w-full max-w-md mx-auto px-6">
      <div className="w-full space-y-8">
        {steps.map((step, index) => {
          const isActive = step.id === state;
          const isCompleted = currentStepIndex > index;
          const isPending = currentStepIndex < index;

          return (
            <div 
              key={step.id} 
              className={`flex items-center space-x-4 transition-all duration-500 ${isPending ? 'opacity-30' : 'opacity-100'}`}
            >
              <div className={`
                w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-500
                ${isActive ? 'border-amber-600 bg-amber-50 text-amber-600 scale-110 shadow-lg' : ''}
                ${isCompleted ? 'border-stone-800 bg-stone-800 text-white' : ''}
                ${isPending ? 'border-stone-200 bg-transparent text-stone-300' : ''}
              `}>
                {isActive ? (
                    <step.icon className="w-5 h-5 animate-pulse" />
                ) : (
                    <step.icon className="w-5 h-5" />
                )}
              </div>
              <div className="flex-1">
                <h3 className={`font-sans font-medium text-lg ${isActive ? 'text-ink' : 'text-stone-400'}`}>
                  {step.label}
                  {isActive && <span className="inline-block w-8 text-left">{dots}</span>}
                </h3>
              </div>
            </div>
          );
        })}
      </div>

      {state === LoadingState.ERROR && (
        <div className="mt-8 p-4 bg-red-50 text-red-600 rounded-lg text-sm text-center border border-red-100">
           Something went wrong. The video might be private or inaccessible. Please try another one.
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { HeroInput } from './components/HeroInput';
import { ArticleReader } from './components/ArticleReader';
import { ProcessingState } from './components/ProcessingState';
import { generateArticleFromVideo, generateCoverImage } from './services/geminiService';
import { LoadingState, ArticleData } from './types';

export default function App() {
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);
  const [article, setArticle] = useState<ArticleData | null>(null);

  const handleAnalyze = useCallback(async (url: string) => {
    setLoadingState(LoadingState.SEARCHING);
    setArticle(null);

    try {
      // Step 1: Search and Analyze
      setLoadingState(LoadingState.ANALYZING);
      // Artificial delay for UX pacing (API is sometimes too fast or we want to show the 'thinking' steps)
      await new Promise(r => setTimeout(r, 1500)); 

      setLoadingState(LoadingState.DRAFTING);
      const data = await generateArticleFromVideo(url);

      // Step 2: Generate Cover Image (Parallel or Sequential)
      if (data.coverImagePrompts) {
        setLoadingState(LoadingState.POLISHING);
        const imageUrl = await generateCoverImage(data.coverImagePrompts);
        if (imageUrl) {
            data.coverImageUrl = imageUrl;
        }
      }

      setArticle(data);
      setLoadingState(LoadingState.COMPLETED);
    } catch (error) {
      console.error(error);
      setLoadingState(LoadingState.ERROR);
    }
  }, []);

  const handleBack = () => {
    setLoadingState(LoadingState.IDLE);
    setArticle(null);
  };

  return (
    <div className="min-h-screen bg-paper text-ink selection:bg-amber-100 selection:text-amber-900">
      {loadingState === LoadingState.IDLE && (
        <HeroInput onAnalyze={handleAnalyze} loadingState={loadingState} />
      )}

      {(loadingState !== LoadingState.IDLE && loadingState !== LoadingState.COMPLETED) && (
        <ProcessingState state={loadingState} />
      )}

      {loadingState === LoadingState.COMPLETED && article && (
        <ArticleReader data={article} onBack={handleBack} />
      )}

      {/* Subtle Footer for Credits */}
      {loadingState === LoadingState.IDLE && (
        <footer className="fixed bottom-6 left-0 right-0 text-center text-xs text-stone-400 font-sans tracking-wide">
           POWERED BY GEMINI 3 PRO PREVIEW
        </footer>
      )}
    </div>
  );
}

