import { GoogleGenAI, Type } from "@google/genai";
import { ArticleData } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY is missing from environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateArticleFromVideo = async (videoUrl: string): Promise<ArticleData> => {
  const ai = getAiClient();

  // 1. Analyze Video & Write Article
  // We use gemini-3-pro-preview for complex reasoning and writing capabilities.

  const systemInstruction = `
    You are a world-class non-fiction author and ghostwriter (Persona: A mix of Malcolm Gladwell, Peter Thiel, and a senior editor at Caixin 财新/Sanlian Life Week 三联生活周刊).

    Your task is to **TRANSFORM** a long-form video (YouTube/Bilibili) into a **comprehensive, book-quality chapter** in Simplified Chinese.

    **CRITICAL RULE: DO NOT SUMMARIZE.** 
    The user wants to read the video, not a summary of it. If the video is 43 minutes long, the article must reflect that depth. Do not compress content. Do not use bullet points for the main body.

    **GUIDELINES:**
    1.  **Fidelity & Detail (Crucial):** 
        -   **Preserve the narrative arc.** If the speaker tells a personal story to illustrate a point, retell that story fully with vivid details.
        -   **Capture Golden Quotes (金句):** You MUST identify the most profound, witty, or insightful sentences spoken by the creator. Quote them directly (using blockquotes) and weave them into the narrative. Do not paraphrase these gems.
        -   **Keep the nuance.** Don't just say "He argued X". Explain *how* he argued X, what examples he used, and what counter-arguments he addressed.
        -   **Technical Depth:** If the video explains a complex concept step-by-step, write it out step-by-step.

    2.  **Structure & Format:**
        -   **Format:** A standalone chapter in a serious non-fiction book.
        -   **Length:** Target **5000 to 8000+ Chinese characters** for long videos. Do not be afraid of length. The longer and more detailed, the better.
        -   **Tone:** Intellectual, immersive, flowery yet precise. Avoid "video script" markers (e.g., "Hi guys", "In this video"). 
        -   **Headings:** Use meaningful, literary subheadings (##) to break up the text.

    3.  **Styling:** 
        -   Use **Blockquotes (>)** for profound sentences or direct quotes from the speaker.
        -   Use **Bold (**)** sparingly, only for defining new terms.

    4.  **Language:** **MUST BE SIMPLIFIED CHINESE (简体中文)**.
  `;

  const prompt = `
    Video URL: ${videoUrl}

    **TASK:**
    1.  Perform a Deep Search to get the full transcript/content of this video.
    2.  Write a **"Deep Read" (深度长文)** adaptation. 

    **REQUIREMENTS:**
    -   **NO SUMMARIES.** This is a replacement for watching the video. 
    -   **GOLDEN QUOTES:** Extract and highlight at least 3-5 direct quotes that represent the core spirit of the video.
    -   Include specific examples, data, jokes, and anecdotes from the video.
    -   Make it flow like a New Yorker article or a detailed book chapter.
    -   If the video is long, the output MUST be long (aim for 10-15 minute reading time).

    Return JSON:
    {
      "title": "A literary, publishing-quality title (Chinese)",
      "subtitle": "A compelling, descriptive subtitle (Chinese)",
      "author": "Original Speaker Name",
      "content": "The full, long-form markdown content (Chinese).",
      "tags": ["Tag1", "Tag2"],
      "coverImagePrompts": "A detailed art direction prompt for an abstract/editorial cover image (English)."
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      // Maximize thinking budget to 32k to allow the model to structure a very long narrative with deep understanding
      thinkingConfig: { thinkingBudget: 32768 }, 
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          subtitle: { type: Type.STRING },
          author: { type: Type.STRING },
          content: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
          coverImagePrompts: { type: Type.STRING },
        },
        required: ["title", "subtitle", "author", "content", "tags", "coverImagePrompts"]
      }
    },
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  let parsedData: any;
  try {
    parsedData = JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse JSON", text);
    throw new Error("Failed to parse AI response");
  }

  // Calculate reading time for Chinese text
  // Average reading speed: ~400-500 characters per minute for deep reading
  const chineseCharCount = parsedData.content.length;
  const estimatedTime = Math.ceil(chineseCharCount / 400);

  const article: ArticleData = {
    ...parsedData,
    sourceUrl: videoUrl,
    estimatedReadingTime: estimatedTime
  };

  return article;
};

export const generateCoverImage = async (imagePrompt: string): Promise<string | undefined> => {
  try {
    const ai = getAiClient();
    // Using gemini-3-pro-image-preview for high quality 16:9 editorial headers
    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: imagePrompt,
        config: {
            imageConfig: {
                aspectRatio: "16:9",
                imageSize: "1K"
            }
        }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
  } catch (e) {
    console.warn("Image generation failed, continuing without image", e);
    return undefined;
  }
  return undefined;
};

import React, { useEffect, useState } from 'react';
import { LoadingState } from '../types';
import { Loader2, Search, Brain, PenTool, Sparkles } from 'lucide-react';

interface ProcessingStateProps {
  state: LoadingState;
}

export const ProcessingState: React.FC<ProcessingStateProps> = ({ state }) => {
  const [dots, setDots] = useState('');

  useEffect(() => {
    const interval = setInterval(() => {
      setDots(prev => prev.length >= 3 ? '' : prev + '.');
    }, 500);
    return () => clearInterval(interval);
  }, []);

  const steps = [
    { id: LoadingState.SEARCHING, label: '正在全网检索视频内容', icon: Search },
    { id: LoadingState.ANALYZING, label: '正在解析叙事逻辑', icon: Brain },
    { id: LoadingState.DRAFTING, label: '深度思考与长文撰写中 (需耗时较长)', icon: PenTool },
    { id: LoadingState.POLISHING, label: '正在进行编辑与润色', icon: Sparkles },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === state);

  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] w-full max-w-md mx-auto px-6">
      <div className="w-full space-y-8">
        {steps.map((step, index) => {
          const isActive = step.id === state;
          const isCompleted = currentStepIndex > index;
          const isPending = currentStepIndex < index;

          return (
            <div 
              key={step.id} 
              className={`flex items-center space-x-4 transition-all duration-500 ${isPending ? 'opacity-30' : 'opacity-100'}`}
            >
              <div className={`
                w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-500
                ${isActive ? 'border-amber-600 bg-amber-50 text-amber-600 scale-110 shadow-lg' : ''}
                ${isCompleted ? 'border-stone-800 bg-stone-800 text-white' : ''}
                ${isPending ? 'border-stone-200 bg-transparent text-stone-300' : ''}
              `}>
                {isActive ? (
                    <step.icon className="w-5 h-5 animate-pulse" />
                ) : (
                    <step.icon className="w-5 h-5" />
                )}
              </div>
              <div className="flex-1">
                <h3 className={`font-sans font-medium text-lg ${isActive ? 'text-ink' : 'text-stone-400'}`}>
                  {step.label}
                  {isActive && <span className="inline-block w-8 text-left">{dots}</span>}
                </h3>
              </div>
            </div>
          );
        })}
      </div>

      {state === LoadingState.ERROR && (
        <div className="mt-8 p-4 bg-red-50 text-red-600 rounded-lg text-sm text-center border border-red-100">
           出错了。可能是视频无法访问，或者内容过于庞大。请重试。
        </div>
      )}
    </div>
  );
};

import React, { useRef, useState } from 'react';
import ReactMarkdown from 'react-markdown';
import { toPng } from 'html-to-image';
// @ts-ignore
import html2pdf from 'html2pdf.js';
import { ArticleData } from '../types';
import { Clock, ArrowLeft, Share2, Youtube, Sparkles, Download, Check, Link as LinkIcon, Image as ImageIcon, FileText } from 'lucide-react';

interface ArticleReaderProps {
  data: ArticleData;
  onBack: () => void;
}

export const ArticleReader: React.FC<ArticleReaderProps> = ({ data, onBack }) => {
  const articleRef = useRef<HTMLElement>(null);
  const [isDownloading, setIsDownloading] = useState(false);
  const [isDownloadingPdf, setIsDownloadingPdf] = useState(false);
  const [showCopied, setShowCopied] = useState(false);

  // Function to handle image download
  const handleDownloadImage = async () => {
    if (articleRef.current === null) {
      return;
    }

    setIsDownloading(true);

    try {
      // 1. Optimize for Speed: Reduce pixelRatio from 2 to 1.5 (still HD, but much faster)
      // 2. Fix Clipping: Enforce a fixed width (800px) and reset layout constraints
      const imageWidth = 800;

      const dataUrl = await toPng(articleRef.current, {
        cacheBust: true,
        backgroundColor: '#f9f7f1', // Ensure paper color background
        pixelRatio: 1.5, // Balanced for speed and quality
        width: imageWidth, // Force canvas width
        style: {
            // CRITICAL: Reset layout constraints on the captured clone to prevent clipping
            // caused by 'mx-auto' or viewport-based sizing.
            margin: '0',
            maxWidth: 'none',
            width: '100%',
            height: 'auto',
            padding: '40px', // Uniform padding for the "Print" look
            transform: 'none', // Reset any potential transforms
        }
      });

      const link = document.createElement('a');
      link.download = `${data.title.replace(/\s+/g, '_').slice(0, 20)}_DeepRead.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to generate image', err);
      alert('抱歉，生成图片时出现错误，请重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleDownloadPdf = () => {
    if (articleRef.current === null) return;

    setIsDownloadingPdf(true);

    const element = articleRef.current;
    const opt = {
        margin:       [15, 15, 15, 15], // mm
        filename:     `${data.title.replace(/\s+/g, '_').slice(0, 20)}_DeepRead.pdf`,
        image:        { type: 'jpeg', quality: 0.98 },
        html2canvas:  { 
            scale: 2, 
            useCORS: true,
            // letterRendering: true, // Sometimes helps with text
            scrollY: 0,
        },
        jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak:    { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // Use a small timeout to allow UI update
    setTimeout(() => {
        html2pdf().set(opt).from(element).save()
        .then(() => setIsDownloadingPdf(false))
        .catch((err: any) => {
            console.error('PDF Generation Error:', err);
            setIsDownloadingPdf(false);
            alert('PDF 生成失败，请重试。');
        });
    }, 100);
  };

  // Function to copy share link
  const handleCopyLink = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('video', data.sourceUrl);

    navigator.clipboard.writeText(url.toString()).then(() => {
      setShowCopied(true);
      setTimeout(() => setShowCopied(false), 2000);
    }).catch(err => {
      console.error('Failed to copy link', err);
    });
  };

  return (
    <div className="min-h-screen bg-paper animate-fade-in pb-24">
      {/* Navigation - Minimalist */}
      <nav className="sticky top-0 z-20 bg-paper/95 backdrop-blur-sm border-b border-stone-200/50 transition-all duration-500 print:hidden">
        <div className="max-w-screen-xl mx-auto px-4 md:px-6 h-16 flex items-center justify-between">
          <button 
            onClick={onBack}
            className="flex items-center space-x-2 text-stone-500 hover:text-ink transition-colors group"
          >
            <ArrowLeft className="w-4 h-4 transform group-hover:-translate-x-1 transition-transform" />
            <span className="hidden md:inline font-sans text-xs tracking-widest font-medium uppercase">Library</span>
            <span className="md:hidden font-sans text-xs tracking-widest font-medium uppercase">Back</span>
          </button>

          <div className="flex items-center space-x-2 md:space-x-4">
            <button 
                onClick={handleCopyLink}
                className="flex items-center space-x-2 px-3 py-1.5 rounded-full hover:bg-stone-100 transition-colors text-stone-500 hover:text-ink"
                title="Copy Link to this Article"
            >
                {showCopied ? <Check className="w-4 h-4 text-green-600" /> : <LinkIcon className="w-4 h-4" />}
                <span className="hidden md:inline text-xs font-sans font-medium tracking-wide">
                    {showCopied ? 'COPIED' : 'SHARE LINK'}
                </span>
            </button>

            <div className="w-px h-6 bg-stone-300 mx-2 hidden md:block"></div>

            <button 
                onClick={handleDownloadPdf}
                disabled={isDownloadingPdf || isDownloading}
                className="flex items-center space-x-2 px-3 py-1.5 rounded-full border border-stone-300 hover:bg-stone-100 transition-colors disabled:opacity-50 text-stone-600"
                title="Save as PDF"
            >
                {isDownloadingPdf ? (
                    <div className="w-4 h-4 border-2 border-stone-400 border-t-stone-600 rounded-full animate-spin" />
                ) : (
                    <FileText className="w-4 h-4" />
                )}
                <span className="hidden md:inline text-xs font-sans font-medium tracking-wide">
                    PDF
                </span>
            </button>

             <button 
                onClick={handleDownloadImage}
                disabled={isDownloading || isDownloadingPdf}
                className="flex items-center space-x-2 px-3 py-1.5 rounded-full bg-ink text-white hover:bg-stone-800 transition-colors disabled:opacity-50"
                title="Save as Image"
             >
                {isDownloading ? (
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                    <ImageIcon className="w-4 h-4" />
                )}
                <span className="hidden md:inline text-xs font-sans font-medium tracking-wide">
                    IMAGE
                </span>
             </button>
          </div>
        </div>
      </nav>

      {/* The Article Container to Capture */}
      <article ref={articleRef} className="max-w-[720px] mx-auto px-6 pt-16 md:pt-24 bg-paper">

        {/* Editorial Header */}
        <header className="mb-14 text-center">
            {/* Tagline / Kicker */}
            <div className="flex items-center justify-center space-x-3 text-accent mb-8">
                {data.tags.slice(0, 1).map(tag => (
                    <span key={tag} className="font-sans text-xs font-bold tracking-[0.2em] uppercase text-amber-700 relative px-4 py-1">
                        <span className="absolute inset-0 border border-amber-900/10 transform -skew-x-12"></span>
                        <span className="relative z-10">{tag}</span>
                    </span>
