          >
            <ArrowLeft className="w-4 h-4 transform group-hover:-translate-x-1 transition-transform" />
            <span className="hidden md:inline font-sans text-xs tracking-widest font-medium uppercase">Library</span>
            <span className="md:hidden font-sans text-xs tracking-widest font-medium uppercase">Back</span>
          </button>

          <div className="flex items-center space-x-2 md:space-x-4">

            <button 
                onClick={handleDownloadPdf}
                disabled={isDownloadingPdf || isDownloading}
                className="flex items-center space-x-2 px-3 py-1.5 rounded-full border border-stone-300 hover:bg-stone-100 transition-colors disabled:opacity-50 text-stone-600"
                title="Save as PDF"
            >
                {isDownloadingPdf ? (
                    <div className="w-4 h-4 border-2 border-stone-400 border-t-stone-600 rounded-full animate-spin" />
                ) : (
                    <FileText className="w-4 h-4" />
                )}
                <span className="hidden md:inline text-xs font-sans font-medium tracking-wide">
                    PDF
                </span>
            </button>

             <button 
                onClick={handleDownloadImage}
                disabled={isDownloading || isDownloadingPdf}
                className="flex items-center space-x-2 px-3 py-1.5 rounded-full bg-ink text-white hover:bg-stone-800 transition-colors disabled:opacity-50"
                title="Save as Image"
             >
                {isDownloading ? (
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                    <ImageIcon className="w-4 h-4" />
                )}
                <span className="hidden md:inline text-xs font-sans font-medium tracking-wide">
                    IMAGE
                </span>
             </button>
          </div>
        </div>
      </nav>

      {/* The Article Container to Capture */}
      <article ref={articleRef} className="max-w-[720px] mx-auto px-6 pt-16 md:pt-24 bg-paper">

        {/* Editorial Header */}
        <header className="mb-14 text-center">
            {/* Tagline / Kicker */}
            <div className="flex items-center justify-center space-x-3 text-accent mb-8">
                {data.tags.slice(0, 1).map(tag => (
                    <span key={tag} className="font-sans text-xs font-bold tracking-[0.2em] uppercase text-amber-700 relative px-4 py-1">
                        <span className="absolute inset-0 border border-amber-900/10 transform -skew-x-12"></span>
                        <span className="relative z-10">{tag}</span>
                    </span>
                ))}
            </div>

            {/* Title */}
            <h1 className="font-serif text-4xl md:text-5xl lg:text-6xl text-ink font-bold leading-tight md:leading-[1.15] mb-6 tracking-tight">
                {data.title}
            </h1>

            {/* Subtitle */}
            <p className="font-sans text-lg md:text-xl text-stone-500 font-light mb-10 max-w-xl mx-auto leading-relaxed">
                {data.subtitle}
            </p>

            {/* Byline */}
            <div className="flex flex-col md:flex-row items-center justify-center gap-4 md:gap-8 text-xs font-sans tracking-widest text-stone-400 border-t border-b border-stone-200/60 py-5 max-w-lg mx-auto uppercase">
                <span className="flex items-center">
                    <span className="text-stone-300 mr-2">AUTHOR</span>
                    <span className="text-ink font-bold">{data.author}</span>
                </span>
                <span className="hidden md:block w-px h-3 bg-stone-300"></span>
                <span className="flex items-center">
                    <Clock className="w-3 h-3 mr-2 text-stone-300" />
                    {data.estimatedReadingTime} MIN READ
                </span>
            </div>
        </header>

        {/* Cover Image - Full Bleed on Mobile, Rounded on Desktop */}
        {data.coverImageUrl && (
            <figure className="mb-16 -mx-6 md:-mx-0 relative group">
                <div className="aspect-[21/9] md:aspect-[2/1] w-full overflow-hidden shadow-sm md:rounded-sm">
                    {/* Note: We use crossOrigin="anonymous" although base64 doesn't need it, just good practice if we switch to URLs */}
                    <img 
                        src={data.coverImageUrl} 
                        alt="Chapter Cover" 
                        className="w-full h-full object-cover filter brightness-[0.98] contrast-[1.02] sepia-[0.05]"
                    />
                </div>
                <figcaption className="mt-3 text-center md:text-right">
                    <span className="inline-flex items-center text-[10px] text-stone-400 font-sans tracking-widest uppercase opacity-70">
                        <Sparkles className="w-2.5 h-2.5 mr-1" /> AI Illustration
                    </span>
                </figcaption>
            </figure>
        )}

        {/* Content Body - The "New Yorker" Style */}
        <div className="
            prose prose-lg md:prose-xl prose-stone mx-auto
            prose-headings:font-sans prose-headings:font-bold prose-headings:tracking-tighter prose-headings:text-ink
            prose-h2:text-3xl prose-h2:mt-16 prose-h2:mb-6
            prose-h3:text-2xl prose-h3:mt-12 prose-h3:mb-4
            prose-p:font-serif prose-p:text-ink prose-p:leading-8 prose-p:text-justify
            prose-a:text-amber-700 prose-a:no-underline prose-a:border-b prose-a:border-amber-700/30 hover:prose-a:border-amber-700 prose-a:transition-all
            prose-blockquote:border-l-2 prose-blockquote:border-accent prose-blockquote:pl-6 prose-blockquote:italic prose-blockquote:font-serif prose-blockquote:text-stone-600 prose-blockquote:bg-transparent
            prose-strong:font-bold prose-strong:text-ink
            prose-li:font-serif prose-li:text-ink

            /* First Letter Drop Cap Logic */
            [&>p:first-of-type]:first-letter:text-6xl
            [&>p:first-of-type]:first-letter:font-bold
            [&>p:first-of-type]:first-letter:text-ink
            [&>p:first-of-type]:first-letter:mr-3
            [&>p:first-of-type]:first-letter:float-left
            [&>p:first-of-type]:first-letter:leading-[0.8]
            [&>p:first-of-type]:first-letter:mt-1
            [&>p:first-of-type]:first-letter:font-serif
        ">
            <ReactMarkdown>{data.content}</ReactMarkdown>
        </div>

        {/* Editorial Footer / End Mark */}
        <div className="mt-24 flex justify-center">
            <span className="text-2xl text-stone-300 font-serif">❦</span>
        </div>

        {/* Source Link */}
        <div className="mt-12 pt-12 border-t border-stone-200 pb-12">
            <div className="bg-white/50 border border-stone-100 rounded-lg p-6 flex flex-col md:flex-row items-center justify-between gap-4 text-center md:text-left">
                <div>
                    <h4 className="font-sans font-bold text-sm text-ink mb-1">Source Material</h4>
                    <p className="font-serif text-sm text-stone-500 italic">Adapted from the original video content.</p>
                </div>
                {/* We render the link but it might not be clickable in a static image, which is fine */}
                <div className="flex items-center text-ink font-semibold space-x-2">
                    <Youtube className="w-4 h-4" />
                    <span className="text-sm font-sans">{data.sourceUrl}</span>
                </div>
            </div>

            <div className="mt-8 text-center">
                 <p className="text-[10px] text-stone-300 font-sans tracking-[0.2em] uppercase">
                    Generated by Video Alchemist
                 </p>
            </div>
        </div>
      </article>
    </div>
  );
};
